/**
 * Inactivity Timer Hook
 * 
 * Tracks user activity and provides callbacks for inactivity warnings and auto-logout.
 * Monitors mouse movement, keyboard input, touch events, and page visibility.
 */

import { useState, useEffect, useCallback, useRef } from 'react';

export const useInactivityTimer = ({
  timeoutMinutes = 30,        // Auto-logout after 30 minutes of inactivity
  warningMinutes = 5,        // Show warning 5 minutes before logout
  onWarning,                 // Callback when warning should be shown
  onTimeout,                 // Callback when user should be logged out
  onActivity,                // Callback when user activity is detected
  enabled = true             // Can be disabled for testing
}) => {
  const [isWarningVisible, setIsWarningVisible] = useState(false);
  const [timeRemaining, setTimeRemaining] = useState(0);
  
  const timeoutRef = useRef(null);
  const warningTimeoutRef = useRef(null);
  const lastActivityRef = useRef(Date.now());
  const countdownRef = useRef(null);

  // Convert minutes to milliseconds
  const timeoutMs = timeoutMinutes * 60 * 1000;
  const warningMs = warningMinutes * 60 * 1000;
  const warningTriggerMs = timeoutMs - warningMs;

  // Reset all timers and update last activity
  const resetTimers = useCallback(() => {
    const now = Date.now();
    lastActivityRef.current = now;

    // Clear existing timers
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
    }
    if (warningTimeoutRef.current) {
      clearTimeout(warningTimeoutRef.current);
    }
    if (countdownRef.current) {
      clearInterval(countdownRef.current);
    }

    // Hide warning if visible
    if (isWarningVisible) {
      setIsWarningVisible(false);
      setTimeRemaining(0);
    }

    // Set warning timer (shows warning before timeout)
    if (warningMinutes > 0 && onWarning) {
      warningTimeoutRef.current = setTimeout(() => {
        setIsWarningVisible(true);
        setTimeRemaining(warningMs);
        
        // Start countdown
        countdownRef.current = setInterval(() => {
          setTimeRemaining(prev => {
            const newTime = prev - 1000;
            if (newTime <= 0) {
              clearInterval(countdownRef.current);
              return 0;
            }
            return newTime;
          });
        }, 1000);

        onWarning();
      }, warningTriggerMs);
    }

    // Set main timeout (auto-logout)
    timeoutRef.current = setTimeout(() => {
      if (onTimeout) {
        onTimeout();
      }
    }, timeoutMs);

    // Notify about activity
    if (onActivity) {
      onActivity();
    }
  }, [timeoutMs, warningMs, warningTriggerMs, warningMinutes, onWarning, onTimeout, onActivity, isWarningVisible]);

  // Handle user activity events
  const handleActivity = useCallback(() => {
    if (!enabled) {return;}
    
    const now = Date.now();
    const timeSinceLastActivity = now - lastActivityRef.current;
    
    // Only reset if significant time has passed (avoid excessive resets)
    if (timeSinceLastActivity > 1000) { // 1 second debounce
      resetTimers();
    }
  }, [enabled, resetTimers]);

  // Extend session (called from warning modal)
  const extendSession = useCallback(() => {
    resetTimers();
  }, [resetTimers]);

  // Force logout (called from warning modal)
  const forceLogout = useCallback(() => {
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
    }
    if (warningTimeoutRef.current) {
      clearTimeout(warningTimeoutRef.current);
    }
    if (countdownRef.current) {
      clearInterval(countdownRef.current);
    }
    
    setIsWarningVisible(false);
    setTimeRemaining(0);
    
    if (onTimeout) {
      onTimeout();
    }
  }, [onTimeout]);

  // Set up activity listeners
  useEffect(() => {
    if (!enabled) {return;}

    const activityEvents = [
      'mousedown',
      'mousemove',
      'keypress',
      'scroll',
      'touchstart',
      'click',
      'keydown',
      'keyup'
    ];

    const handleActivityEvent = (event) => {
      // Ignore certain events that don't indicate real user activity
      if (event.type === 'mousemove' && event.movementX === 0 && event.movementY === 0) {
        return;
      }
      
      handleActivity();
    };

    // Add event listeners
    activityEvents.forEach(event => {
      document.addEventListener(event, handleActivityEvent, { passive: true });
    });

    // Handle page visibility changes
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible') {
        handleActivity();
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);

    // Initialize timers
    resetTimers();

    // Cleanup
    return () => {
      activityEvents.forEach(event => {
        document.removeEventListener(event, handleActivityEvent);
      });
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
      }
      if (warningTimeoutRef.current) {
        clearTimeout(warningTimeoutRef.current);
      }
      if (countdownRef.current) {
        clearInterval(countdownRef.current);
      }
    };
  }, [enabled, handleActivity, resetTimers]);

  // Format remaining time for display
  const formatTimeRemaining = useCallback((milliseconds) => {
    const totalSeconds = Math.ceil(milliseconds / 1000);
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;
    
    if (minutes > 0) {
      return `${minutes}:${seconds.toString().padStart(2, '0')}`;
    }
    return `${seconds}s`;
  }, []);

  return {
    isWarningVisible,
    timeRemaining,
    formattedTimeRemaining: formatTimeRemaining(timeRemaining),
    extendSession,
    forceLogout,
    resetTimers,
    lastActivity: lastActivityRef.current
  };
};
