/**
 * Inactivity Provider
 * 
 * Global provider that manages user session inactivity across the entire application.
 * Integrates with token service for secure session management.
 */

import React, { createContext, useContext, useCallback } from 'react';
import { useInactivityTimer } from '@/shared/hooks/useInactivityTimer';
import InactivityWarningModal from '@/shared/components/InactivityWarningModal.jsx';
import { tokenService } from '@/features/auth/services/tokenService.js';
import { logger } from '@/shared/utils/logger.js';

const InactivityContext = createContext(null);

export const useInactivity = () => {
  const context = useContext(InactivityContext);
  if (!context) {
    throw new Error('useInactivity must be used within an InactivityProvider');
  }
  return context;
};

const InactivityProvider = ({
  children,
  timeoutMinutes = 30,
  warningMinutes = 5,
  enabled = import.meta.env.MODE === 'production' // Only enable in production
}) => {
  // Handle session timeout - auto logout
  const handleTimeout = useCallback(() => {
    logger.warn('Session timeout - logging out user due to inactivity');

    try {
      // Clear all session data
      tokenService.safeLogout();

      // Show a brief message before redirecting
      if (typeof window !== 'undefined') {
        // You could show a toast message here if needed
        logger.info('Redirecting to login due to inactivity timeout');

        // Redirect to login page
        setTimeout(() => {
          window.location.href = '/login?reason=timeout';
        }, 100);
      }
    } catch (error) {
      logger.error('Error during inactivity logout', error);
      // Fallback redirect
      if (typeof window !== 'undefined') {
        window.location.href = '/login';
      }
    }
  }, []);

  // Handle warning display
  const handleWarning = useCallback(() => {
    logger.info('Session timeout warning triggered');
    // The modal will be shown automatically by the useInactivityTimer hook
  }, []);

  // Handle user activity
  const handleActivity = useCallback(() => {
    // Optional: You could track activity metrics here
    // logger.debug('User activity detected');
  }, []);

  // Use the inactivity timer hook
  const {
    isWarningVisible,
    timeRemaining,
    formattedTimeRemaining,
    extendSession,
    forceLogout
  } = useInactivityTimer({
    timeoutMinutes,
    warningMinutes,
    onWarning: handleWarning,
    onTimeout: handleTimeout,
    onActivity: handleActivity,
    enabled
  });

  // Handle extending session from warning modal
  const handleExtendSession = useCallback(() => {
    logger.info('User extended session from warning modal');
    extendSession();
  }, [extendSession]);

  // Handle immediate logout from warning modal
  const handleLogoutNow = useCallback(() => {
    logger.info('User chose to logout immediately from warning modal');
    forceLogout();
  }, [forceLogout]);

  // Context value
  const contextValue = {
    isWarningVisible,
    timeRemaining,
    formattedTimeRemaining,
    timeoutMinutes,
    warningMinutes,
    enabled,
    extendSession: handleExtendSession,
    forceLogout: handleLogoutNow,
    resetTimers: extendSession // Alias for convenience
  };

  return (
    <InactivityContext.Provider value={contextValue}>
      {children}

      {/* Global Inactivity Warning Modal */}
      <InactivityWarningModal
        isVisible={isWarningVisible}
        timeRemaining={timeRemaining}
        formattedTimeRemaining={formattedTimeRemaining}
        onExtendSession={handleExtendSession}
        onLogoutNow={handleLogoutNow}
      />
    </InactivityContext.Provider>
  );
};

export default InactivityProvider;
