/**
 * Inactivity Warning Modal Component
 * 
 * Shows a warning when user session is about to expire due to inactivity.
 * Allows user to extend session or log out immediately.
 */

import React from 'react';
import { useTranslation } from 'react-i18next';
import { createPortal } from 'react-dom';

const InactivityWarningModal = ({ 
  isVisible, 
  timeRemaining, 
  formattedTimeRemaining,
  onExtendSession,
  onLogoutNow 
}) => {
  const { t } = useTranslation();

  if (!isVisible) {return null;}

  const handleExtendSession = () => {
    onExtendSession();
  };

  const handleLogoutNow = () => {
    onLogoutNow();
  };

  const handleOverlayClick = (e) => {
    if (e.target === e.currentTarget) {
      // Don't close on overlay click - user must make a choice
      return;
    }
  };

  return createPortal(
    <div
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundColor: 'rgba(0, 0, 0, 0.7)',
        backdropFilter: 'blur(4px)',
        WebkitBackdropFilter: 'blur(4px)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        zIndex: 999999,
        padding: '20px'
      }}
      onClick={handleOverlayClick}
    >
      <div
        style={{
          backgroundColor: 'var(--card)',
          borderRadius: '16px',
          maxWidth: '480px',
          width: '100%',
          padding: '32px',
          boxShadow: '0 25px 50px rgba(0, 0, 0, 0.25)',
          border: '1px solid var(--border-primary)',
          textAlign: 'center',
          animation: 'modalSlideIn 0.3s ease-out'
        }}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Warning Icon */}
        <div style={{
          width: '64px',
          height: '64px',
          backgroundColor: 'rgba(245, 158, 11, 0.1)',
          borderRadius: '50%',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          margin: '0 auto 24px'
        }}>
          <span 
            className="material-symbols-outlined" 
            style={{
              fontSize: '32px',
              color: '#f59e0b'
            }}
          >
            warning
          </span>
        </div>

        {/* Title */}
        <h2 style={{
          fontSize: '1.5rem',
          fontWeight: '600',
          color: 'var(--text-primary)',
          margin: '0 0 16px',
          lineHeight: '1.2'
        }}>
          {t('sessionTimeoutWarning', { 
            ns: 'common', 
            defaultValue: 'Session Timeout Warning' 
          })}
        </h2>

        {/* Message */}
        <p style={{
          fontSize: '1rem',
          color: 'var(--text-secondary)',
          margin: '0 0 24px',
          lineHeight: '1.5'
        }}>
          {t('sessionTimeoutMessage', { 
            ns: 'common', 
            defaultValue: 'Your session will expire due to inactivity. You will be automatically logged out.' 
          })}
        </p>

        {/* Countdown Timer */}
        <div style={{
          fontSize: '2rem',
          fontWeight: '700',
          color: timeRemaining < 60000 ? '#ef4444' : '#f59e0b', // Red if less than 1 minute
          margin: '0 0 32px',
          fontFamily: 'monospace'
        }}>
          {formattedTimeRemaining}
        </div>

        {/* Action Buttons */}
        <div style={{
          display: 'flex',
          gap: '12px',
          flexDirection: 'column',
          sm: {
            flexDirection: 'row'
          }
        }}>
          <button
            onClick={handleExtendSession}
            style={{
              flex: 1,
              padding: '14px 24px',
              backgroundColor: 'var(--accent)',
              color: 'white',
              border: 'none',
              borderRadius: '8px',
              fontSize: '1rem',
              fontWeight: '600',
              cursor: 'pointer',
              transition: 'all 0.2s ease',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px'
            }}
            onMouseOver={(e) => {
              e.target.style.backgroundColor = 'var(--accent-hover)';
              e.target.style.transform = 'translateY(-1px)';
            }}
            onMouseOut={(e) => {
              e.target.style.backgroundColor = 'var(--accent)';
              e.target.style.transform = 'translateY(0)';
            }}
          >
            <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>
              refresh
            </span>
            {t('extendSession', { ns: 'common', defaultValue: 'Stay Logged In' })}
          </button>

          <button
            onClick={handleLogoutNow}
            style={{
              flex: 1,
              padding: '14px 24px',
              backgroundColor: 'transparent',
              color: 'var(--text-secondary)',
              border: '1px solid var(--border-primary)',
              borderRadius: '8px',
              fontSize: '1rem',
              fontWeight: '600',
              cursor: 'pointer',
              transition: 'all 0.2s ease',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px'
            }}
            onMouseOver={(e) => {
              e.target.style.backgroundColor = 'var(--bg-hover)';
              e.target.style.borderColor = 'var(--border-secondary)';
            }}
            onMouseOut={(e) => {
              e.target.style.backgroundColor = 'transparent';
              e.target.style.borderColor = 'var(--border-primary)';
            }}
          >
            <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>
              logout
            </span>
            {t('logoutNow', { ns: 'common', defaultValue: 'Logout Now' })}
          </button>
        </div>

        {/* Additional Info */}
        <p style={{
          fontSize: '0.875rem',
          color: 'var(--text-muted)',
          margin: '24px 0 0',
          lineHeight: '1.4'
        }}>
          {t('sessionTimeoutInfo', { 
            ns: 'common', 
            defaultValue: 'For your security, we automatically log out inactive sessions to protect your account.' 
          })}
        </p>
      </div>
    </div>,
    document.body
  );
};

export default InactivityWarningModal;
